[{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"EditURL = \"../../../examples/bratu.jl\"","category":"page"},{"location":"generated/bratu/#1D-bratu-equation","page":"Bratu 1D","title":"1D bratu equation","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"using NewtonKrylov, Krylov\nusing KrylovPreconditioners\nusing SparseArrays, LinearAlgebra\nusing CairoMakie\n\nfunction bratu!(res, y, Δx, λ)\n    N = length(y)\n    for i in 1:N\n        y_l = i == 1 ? zero(eltype(y)) : y[i - 1]\n        y_r = i == N ? zero(eltype(y)) : y[i + 1]\n        y′′ = (y_r - 2y[i] + y_l) / Δx^2\n\n        res[i] = y′′ + λ * exp(y[i]) # = 0\n    end\n    return nothing\nend\n\nfunction bratu(y, dx, λ)\n    res = similar(y)\n    bratu!(res, y, dx, λ)\n    return res\nend\n\nfunction true_sol_bratu(x)\n    # for λ = 3.51382, 2nd sol θ = 4.8057\n    θ = 4.79173\n    return -2 * log(cosh(θ * (x - 0.5) / 2) / (cosh(θ / 4)))\nend\n\nconst N = 10_000\nconst λ = 3.51382\nconst dx = 1 / (N + 1) # Grid-spacing\n\nx = LinRange(0.0 + dx, 1.0 - dx, N)\nu₀ = sin.(x .* π)\n\nreference = true_sol_bratu.(x)\n\nuₖ_1 = newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = CgSolver,\n)\n\nuₖ_2 = newton_krylov(\n    (u) -> bratu(u, dx, λ),\n    copy(u₀);\n    Solver = CgSolver\n)\n\nϵ1 = abs2.(uₖ_1 .- reference)\nϵ2 = abs2.(uₖ_1 .- reference)","category":"page"},{"location":"generated/bratu/#Solving-with-a-fixed-forcing","page":"Bratu 1D","title":"Solving with a fixed forcing","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = CgSolver,\n    forcing = NewtonKrylov.Fixed()\n)","category":"page"},{"location":"generated/bratu/#Solving-with-no-forcing","page":"Bratu 1D","title":"Solving with no forcing","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = CgSolver,\n    forcing = nothing\n)","category":"page"},{"location":"generated/bratu/#Solve-using-GMRES-–-very-slow","page":"Bratu 1D","title":"Solve using GMRES – very slow","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"@time newton_krylov!(\n\t(res, u) -> bratu!(res, u, dx, λ),\n\tcopy(u₀), similar(u₀);\n\tSolver = GmresSolver,\n)","category":"page"},{"location":"generated/bratu/#Solve-using-GMRES-ILU-Preconditoner","page":"Bratu 1D","title":"Solve using GMRES + ILU Preconditoner","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"@time newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = GmresSolver,\n    N = (J) -> ilu(collect(J)), # Assembles the full Jacobian\n    ldiv = true,\n)","category":"page"},{"location":"generated/bratu/#Solve-using-FGMRES-ILU-Preconditoner","page":"Bratu 1D","title":"Solve using FGMRES + ILU Preconditoner","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"@time newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = FgmresSolver,\n    N = (J) -> ilu(collect(J)), # Assembles the full Jacobian\n    ldiv = true,\n)","category":"page"},{"location":"generated/bratu/#Solve-using-FGMRES-GMRES-Preconditoner","page":"Bratu 1D","title":"Solve using FGMRES + GMRES Preconditoner","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"struct GmresPreconditioner{JOp}\n    J::JOp\n    itmax::Int\nend\n\nfunction LinearAlgebra.mul!(y, P::GmresPreconditioner, x)\n    sol, _ = gmres(P.J, x; P.itmax)\n    return copyto!(y, sol)\nend\n\n@time newton_krylov!(\n    (res, u) -> bratu!(res, u, dx, λ),\n    copy(u₀), similar(u₀);\n    Solver = FgmresSolver,\n    N = (J) -> GmresPreconditioner(J, 30),\n)","category":"page"},{"location":"generated/bratu/#Explodes..","page":"Bratu 1D","title":"Explodes..","text":"","category":"section"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"newton_krylov!(\n\t(res, u) -> bratu!(res, u, dx, λ),\n\tcopy(u₀), similar(u₀);\n\tverbose = 1,\n\tSolver = CglsSolver, # CgneSolver\n)","category":"page"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"newton_krylov!(\n\t(res, u) -> bratu!(res, u, dx, λ),\n\tcopy(u₀), similar(u₀);\n\tverbose = 1,\n\tSolver = BicgstabSolver,\n\tη_max = nothing\n)","category":"page"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"","category":"page"},{"location":"generated/bratu/","page":"Bratu 1D","title":"Bratu 1D","text":"This page was generated using Literate.jl.","category":"page"},{"location":"#NewtonKrylov.jl","page":"Home","title":"NewtonKrylov.jl","text":"","category":"section"},{"location":"#API","page":"Home","title":"API","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"newton_krylov!\nNewtonKrylov.EisenstatWalker","category":"page"},{"location":"#NewtonKrylov.newton_krylov!","page":"Home","title":"NewtonKrylov.newton_krylov!","text":"Arguments\n\nF!: F!(res, u) solves res = F(u) = 0\nu: Initial guess\nres: Temporary for residual\n\nKeyword Arguments\n\ntol_rel: Relative tolerance\ntol_abs: Absolute tolerance\nmax_niter: Maximum number of iterations\nforcing: Maximum forcing term for inexact Newton.          If nothing an exact Newton method is used.   \n\n\n\n\n\n","category":"function"},{"location":"#NewtonKrylov.EisenstatWalker","page":"Home","title":"NewtonKrylov.EisenstatWalker","text":"Compute the Eisenstat-Walker forcing term for n > 0\n\n\n\n\n\n","category":"type"}]
